import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { addDoc } from "../../api/documentApi";
import api from "../../api/axios";

export default function AddDocument() {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    title: "",
    docType: "RC_BOOK",
    referenceNo: "",
    vehicle: "",
    status: "AVAILABLE",
    location: "",
    notes: "",
  });

  const getVehicleNumber = (v) =>
    v?.vehicleNumber || v?.vehicle_number || v?.registrationNo || v?.regNo || "";

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const vRes = await api.get("/vehicles");
        setVehicles(vRes.data || []);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load vehicles");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, []);

  const submit = async (e) => {
    e.preventDefault();

    try {
      await addDoc({
        title: form.title,
        docType: form.docType,
        referenceNo: form.referenceNo,
        status: form.status,
        location: form.location,
        notes: form.notes,
        vehicle: form.vehicle || undefined, // optional
      });

      alert("Document added!");
      navigate("/documents");
    } catch (err) {
      alert(err.response?.data?.message || "Add failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Add Physical Document</div>
          <div className="pageSub">Create a new document record</div>
        </div>
      </div>
      {loading && <div className="card cardPad" style={{ textAlign: "center", color: "var(--text-light)" }}>Loading...</div>}

      <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Title</label>
          <input
            value={form.title}
            onChange={(e) => setForm({ ...form, title: e.target.value })}
            className="input"
            required
          />

          <label className="label" style={{ marginTop: 20 }}>Type</label>
          <select
            value={form.docType}
            onChange={(e) => setForm({ ...form, docType: e.target.value })}
            className="select"
          >
            <option value="RC_BOOK">RC Book</option>
            <option value="INSURANCE">Insurance</option>
            <option value="TRANSFER_FORM">Transfer Form</option>
            <option value="EMISSION">Emission</option>
            <option value="SERVICE_BOOK">Service Book</option>
            <option value="OTHER">Other</option>
          </select>

          <label className="label" style={{ marginTop: 20 }}>Reference No (optional)</label>
          <input
            value={form.referenceNo}
            onChange={(e) => setForm({ ...form, referenceNo: e.target.value })}
            className="input"
          />

          <label className="label" style={{ marginTop: 20 }}>Vehicle (optional)</label>
          <select
            value={form.vehicle}
            onChange={(e) => setForm({ ...form, vehicle: e.target.value })}
            className="select"
          >
            <option value="">-- none --</option>
            {vehicles.map((v) => {
              const vNum = getVehicleNumber(v);
              return (
                <option key={v._id} value={v._id}>
                  {v.brand} {v.type || ""} ({v.year}){vNum ? ` - ${vNum}` : ""}
                </option>
              );
            })}
          </select>

          <label className="label" style={{ marginTop: 20 }}>Status</label>
          <select
            value={form.status}
            onChange={(e) => setForm({ ...form, status: e.target.value })}
            className="select"
          >
            <option value="AVAILABLE">AVAILABLE</option>
            <option value="IN_USE">IN_USE</option>
            <option value="MISSING">MISSING</option>
            <option value="ARCHIVED">ARCHIVED</option>
          </select>

          <label className="label" style={{ marginTop: 20 }}>Location</label>
          <input
            value={form.location}
            onChange={(e) => setForm({ ...form, location: e.target.value })}
            className="input"
            required
          />

          <label className="label" style={{ marginTop: 20 }}>Note</label>
          <textarea
            value={form.notes}
            onChange={(e) => setForm({ ...form, notes: e.target.value })}
            rows={3}
            className="textarea"
          />

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" className="btn btnPrimary">Save</button>
            <button type="button" onClick={() => navigate("/documents")} className="btn">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}
